protected JavaType _typeFromId(String id, DatabindContext ctxt) throws IOException {
    // Obtain the TypeFactory instance from the context
    TypeFactory tf = ctxt.getTypeFactory();

    // Check for generic type identifiers
    if (id.indexOf('<') > 0) {
        // If a generic type ID, try to construct the JavaType from its canonical form
        JavaType t = tf.constructFromCanonical(id);
        if (t != null) {
